import ChartJS from 'chart.js/auto';

function LineChart({ data = [], labelKey = 'time', datasets = [], title = '', height = 'h-64' }) {
  const canvasRef = useRef(null);
  const chartRef = useRef(null);

  useEffect(() => {
    if (!canvasRef.current || data.length === 0) return;

    if (chartRef.current) {
      const chart = chartRef.current;
      chart.data.labels = data.map(p => p[labelKey]);
      datasets.forEach((ds, i) => {
        chart.data.datasets[i].data = data.map(p => p[ds.key]);
      });
      chart.update('none');
      return;
    }


    chartRef.current = new ChartJS(canvasRef.current, {
      type: 'line',
      data: {
        labels: data.map(p => p[labelKey]),
        datasets: datasets.map(ds => ({
          label: ds.label,
          data: data.map(p => p[ds.key]),
          borderColor: ds.color,
          backgroundColor: ds.color + '18',
          tension: 0.35,
          fill: true,
          pointRadius: 2,
          borderWidth: 2
        }))
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        animation: false,
        plugins: {
          legend: { labels: { color: '#a1a1aa', usePointStyle: true, pointStyle: 'circle', padding: 16 } }
        },
        scales: {
          x: { ticks: { color: '#52525b', font: { size: 10 } }, grid: { color: '#27272a' } },
          y: { ticks: { color: '#52525b', font: { size: 10 } }, grid: { color: '#27272a' } }
        }
      }
    });

    return () => {
      if (chartRef.current) {
        chartRef.current.destroy();
        chartRef.current = null;
      }
    };
  }, [data, datasets]);

  return (
    <div className="bg-zinc-900/50 rounded-xl border border-zinc-800/50 p-5">
      {title && <h3 className="text-sm font-medium text-zinc-300 mb-3">{title}</h3>}
      <div className={height}>
        <canvas ref={canvasRef} />
      </div>
    </div>
  );
}

