function App() {
  const { data } = useNodeRed();
  const [tab, setTab] = useState(0);
  const points = data || [];

  const tabs = [
    { label: 'Overview', icon: '\u25a6' },
    { label: 'Environment', icon: '\u25cb' },
    { label: 'System', icon: '\u25a1' }
  ];

  return (
    <Page>
      <div className="max-w-5xl mx-auto px-6 py-8">

        <Header title="fromcubes charts" subtitle={points.length + ' data points \u2022 live'} />

        <div className="flex gap-1 mb-6 bg-zinc-900/50 rounded-lg p-1 w-fit">
          {tabs.map((t, i) => (
            <button
              key={i}
              onClick={() => setTab(i)}
              className={`px-4 py-2 rounded-md text-sm transition-all ${
                tab === i
                  ? 'bg-zinc-800 text-zinc-100 shadow-sm'
                  : 'text-zinc-500 hover:text-zinc-300'
              }`}
            >{t.icon} {t.label}</button>
          ))}
        </div>

        {tab === 0 && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            <LineChart
              data={points}
              title="Temperature"
              datasets={[{ key: 'temp', label: 'Temp (\u00b0C)', color: '#22d3ee' }]}
            />
            <LineChart
              data={points}
              title="Humidity"
              datasets={[{ key: 'humidity', label: 'Humidity (%)', color: '#a78bfa' }]}
            />
            <LineChart
              data={points}
              title="CPU Usage"
              datasets={[{ key: 'cpu', label: 'CPU (%)', color: '#f97316' }]}
            />
            <LineChart
              data={points}
              title="Memory"
              datasets={[{ key: 'memory', label: 'Memory (%)', color: '#34d399' }]}
            />
          </div>
        )}

        {tab === 1 && (
          <div className="space-y-4">
            <LineChart
              data={points}
              title="Temperature & Humidity"
              height="h-80"
              datasets={[
                { key: 'temp', label: 'Temp (\u00b0C)', color: '#22d3ee' },
                { key: 'humidity', label: 'Humidity (%)', color: '#a78bfa' }
              ]}
            />
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-zinc-900/50 rounded-xl border border-zinc-800/50 p-5">
                <div className="text-xs text-zinc-500 uppercase tracking-wider">Current Temp</div>
                <div className="text-3xl font-bold text-cyan-400 mt-2">
                  {points.length > 0 ? points[points.length - 1].temp : '--'}
                  <span className="text-sm font-normal text-zinc-500 ml-1">\u00b0C</span>
                </div>
              </div>
              <div className="bg-zinc-900/50 rounded-xl border border-zinc-800/50 p-5">
                <div className="text-xs text-zinc-500 uppercase tracking-wider">Current Humidity</div>
                <div className="text-3xl font-bold text-violet-400 mt-2">
                  {points.length > 0 ? points[points.length - 1].humidity : '--'}
                  <span className="text-sm font-normal text-zinc-500 ml-1">%</span>
                </div>
              </div>
            </div>
          </div>
        )}

        {tab === 2 && (
          <div className="space-y-4">
            <LineChart
              data={points}
              title="CPU & Memory"
              height="h-80"
              datasets={[
                { key: 'cpu', label: 'CPU (%)', color: '#f97316' },
                { key: 'memory', label: 'Memory (%)', color: '#34d399' }
              ]}
            />
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-zinc-900/50 rounded-xl border border-zinc-800/50 p-5">
                <div className="text-xs text-zinc-500 uppercase tracking-wider">Current CPU</div>
                <div className="text-3xl font-bold text-orange-400 mt-2">
                  {points.length > 0 ? points[points.length - 1].cpu : '--'}
                  <span className="text-sm font-normal text-zinc-500 ml-1">%</span>
                </div>
              </div>
              <div className="bg-zinc-900/50 rounded-xl border border-zinc-800/50 p-5">
                <div className="text-xs text-zinc-500 uppercase tracking-wider">Current Memory</div>
                <div className="text-3xl font-bold text-emerald-400 mt-2">
                  {points.length > 0 ? points[points.length - 1].memory : '--'}
                  <span className="text-sm font-normal text-zinc-500 ml-1">%</span>
                </div>
              </div>
            </div>
          </div>
        )}

      </div>
    </Page>
  );
}
